func TestIntakeBlockedSetsOperatorOverrideTrue(t *testing.T) {
	inner, candidate, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatal("executor must not run when intake parks the bead")
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// Simulate a bead that was previously parked to proposed.
	require.NoError(t, inner.SetLifecycleStatus(candidate.ID, bead.StatusProposed, bead.LifecycleTransitionOptions{
		OperatorRequired: true,
		Reason:           "readiness block",
		Actor:            "worker",
		Source:           "ddx work",
	}))

	// Record an intake.blocked event from the previous readiness check.
	_ = inner.AppendEvent(candidate.ID, bead.BeadEvent{
		Kind:      "intake.blocked",
		Summary:   "ambiguous_scope",
		Body:      `{"fingerprint":"abc123","reason":"ambiguous_scope","decision_source":"pre_claim_intake","policy_mode":"block","decision":"park"}`,
		Actor:     "worker",
		Source:    "ddx work",
		CreatedAt: time.Now().UTC(),
	})

	// Simulate operator promotion from proposed to open.
	require.NoError(t, inner.SetLifecycleStatus(candidate.ID, bead.StatusOpen, bead.LifecycleTransitionOptions{
		Reason: "operator accepted",
		Actor:  "reviewer",
		Source: "web-ui",
	}))
	_ = inner.AppendEvent(candidate.ID, bead.BeadEvent{
		Kind:      "triaged",
		Summary:   "operator accepted proposed bead",
		Body:      `{"from_status":"proposed","to_status":"open","operator_required":true,"accepted_fingerprint":"abc123","accepted_prompt_fingerprint":"xyz"}`,
		Actor:     "reviewer",
		Source:    "web-ui",
		CreatedAt: time.Now().UTC(),
	})

	// Run readiness again - it should see operator promotion and skip downgrade,
	// but still write an intake.blocked entry with operator_override=true.
	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: candidate.ID,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "ambiguous_scope",
				Detail:  "ambiguous scope requires human review",
			}, nil
		},
	})
	require.NoError(t, err)

	// Bead should remain open (not downgraded to proposed due to operator promotion).
	got, err := inner.Get(candidate.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status)

	// Check that the intake.blocked event has operator_override=true.
	events, err := inner.Events(candidate.ID)
	require.NoError(t, err)
	found := false
	for _, ev := range events {
		if ev.Kind != "intake.blocked" {
			continue
		}
		var body map[string]any
		require.NoError(t, json.Unmarshal([]byte(ev.Body), &body))
		// Check that operator_override field is present and true.
		operatorOverride, ok := body["operator_override"].(bool)
		if ok && operatorOverride {
			found = true
			break
		}
	}
	assert.True(t, found, "intake.blocked entry when operator promoted must have operator_override=true")
}

func TestIntakeBlockedSetsOperatorOverrideFalse(t *testing.T) {
