		Reason:           "readiness block",
		Actor:            "worker",
		Source:           "ddx work",
	}))

	// Record an intake.blocked event from the previous readiness check.
	_ = inner.AppendEvent(candidate.ID, bead.BeadEvent{
		Kind:      "intake.blocked",
		Summary:   "ambiguous_scope",
		Body:      `{"fingerprint":"abc123","reason":"ambiguous_scope","decision_source":"pre_claim_intake","policy_mode":"block","decision":"park"}`,
		Actor:     "worker",
		Source:    "ddx work",
		CreatedAt: time.Now().UTC(),
	})

	// Simulate operator promotion from proposed to open via a triaged event.
	_ = inner.AppendEvent(candidate.ID, bead.BeadEvent{
		Kind:      "triaged",
		Summary:   "operator accepted proposed bead",
		Body:      `{"from_status":"proposed","to_status":"open","operator_required":true,"actor":"reviewer","source":"web-ui"}`,
		Actor:     "reviewer",
		Source:    "web-ui",
		CreatedAt: time.Now().UTC(),
	})

	// Promote the bead to open (as the operator would do).
	require.NoError(t, inner.SetLifecycleStatus(candidate.ID, bead.StatusOpen, bead.LifecycleTransitionOptions{
		Reason: "operator accepted",
		Actor:  "reviewer",
		Source: "web-ui",
	}))

	// Run readiness again - it should see operator promotion and skip downgrade,
	// but still write an intake.blocked entry with operator_override=true.
	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:         true,
		TargetBeadID: candidate.ID,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
